"use client"

import useSWR from "swr"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Progress } from "@/components/ui/progress"
import { Skeleton } from "@/components/ui/skeleton"
import { BarChart3, Users, Clock } from "lucide-react"

interface Election {
  id: string
  title: string
  description: string
  status: string
  startDate: Date
  endDate: Date
  parties: Array<{ id: string; name: string; voteCount: number }>
  totalVotes: number
}

export function ElectionCommissionMonitor() {
  const { data, isLoading } = useSWR("/api/elections", async (url) => {
    const response = await fetch(url)
    return response.json()
  })

  const elections: Election[] = data?.elections || []

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <BarChart3 className="w-5 h-5" />
          Election Monitoring
        </CardTitle>
        <CardDescription>Real-time voting statistics and election progress</CardDescription>
      </CardHeader>
      <CardContent>
        {isLoading ? (
          <div className="space-y-4">
            {[1, 2].map((i) => (
              <Skeleton key={i} className="h-48" />
            ))}
          </div>
        ) : elections.length === 0 ? (
          <p className="text-gray-500 py-8 text-center">No elections yet</p>
        ) : (
          <div className="space-y-6">
            {elections.map((election) => {
              const totalVotes = election.totalVotes || 1
              return (
                <div key={election.id} className="border rounded-lg p-4 space-y-4">
                  <div className="flex items-start justify-between">
                    <div>
                      <h3 className="font-semibold text-lg">{election.title}</h3>
                      <p className="text-sm text-gray-600">{election.description}</p>
                    </div>
                    <Badge variant={election.status === "active" ? "default" : "secondary"}>{election.status}</Badge>
                  </div>

                  {/* Voting Progress */}
                  <div className="bg-gray-50 p-3 rounded-lg space-y-2">
                    <div className="flex items-center justify-between text-sm">
                      <span className="flex items-center gap-2">
                        <Users className="w-4 h-4" />
                        Total Votes
                      </span>
                      <span className="font-bold">{election.totalVotes}</span>
                    </div>

                    {/* Party Results */}
                    <div className="space-y-2 mt-3">
                      {election.parties.map((party) => {
                        const percentage = Math.round((party.voteCount / totalVotes) * 100)
                        return (
                          <div key={party.id} className="space-y-1">
                            <div className="flex items-center justify-between text-sm">
                              <span>{party.name}</span>
                              <span className="font-semibold">
                                {party.voteCount} ({percentage}%)
                              </span>
                            </div>
                            <Progress value={percentage} className="h-2" />
                          </div>
                        )
                      })}
                    </div>
                  </div>

                  {/* Timeline */}
                  <div className="flex items-center gap-2 text-xs text-gray-600">
                    <Clock className="w-4 h-4" />
                    <span>{new Date(election.startDate).toLocaleDateString()}</span>
                    <span>→</span>
                    <span>{new Date(election.endDate).toLocaleDateString()}</span>
                  </div>
                </div>
              )
            })}
          </div>
        )}
      </CardContent>
    </Card>
  )
}
